import { requireAuth } from '@/lib/supabase/server';
import { createClient } from '@/lib/supabase/server';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Users, Building2, DollarSign, Activity } from 'lucide-react';

export default async function AdminDashboard() {
    const profile = await requireAuth();
    const supabase = await createClient();

    // Fetch admin metrics
    const [usersRes, orgsRes, transactionsRes] = await Promise.all([
        supabase.from('profiles').select('id', { count: 'exact' }),
        supabase.from('organizations').select('id', { count: 'exact' }),
        supabase.from('financial_transactions').select('amount, type'),
    ]);

    const totalUsers = usersRes.count || 0;
    const totalOrgs = orgsRes.count || 0;
    const transactions = transactionsRes.data || [];

    const totalRevenue = transactions
        .filter((t: any) => t.type === 'income' || t.type === 'entrada')
        .reduce((sum: number, t: any) => sum + (t.amount || 0), 0);

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold">Dashboard Administrativo</h1>
                <p className="text-muted-foreground">Visão geral da plataforma</p>
            </div>

            {/* Stats Cards */}
            <div className="grid gap-4 md:grid-cols-4">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Total de Usuários</CardTitle>
                        <Users className="h-4 w-4 text-muted-foreground" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{totalUsers}</div>
                        <p className="text-xs text-muted-foreground">Usuários registrados</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Organizações</CardTitle>
                        <Building2 className="h-4 w-4 text-muted-foreground" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{totalOrgs}</div>
                        <p className="text-xs text-muted-foreground">Clínicas ativas</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Receita Total</CardTitle>
                        <DollarSign className="h-4 w-4 text-muted-foreground" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">
                            {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(totalRevenue)}
                        </div>
                        <p className="text-xs text-muted-foreground">Soma de transações</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Status</CardTitle>
                        <Activity className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-500">Online</div>
                        <p className="text-xs text-muted-foreground">Sistema operacional</p>
                    </CardContent>
                </Card>
            </div>

            {/* Quick Actions */}
            <Card>
                <CardHeader>
                    <CardTitle>Ações Rápidas</CardTitle>
                </CardHeader>
                <CardContent className="grid gap-4 md:grid-cols-3">
                    <div className="p-4 border rounded-lg hover:bg-muted/50 cursor-pointer transition-colors">
                        <h3 className="font-medium">Gerenciar Usuários</h3>
                        <p className="text-sm text-muted-foreground">Ver e editar usuários da plataforma</p>
                    </div>
                    <div className="p-4 border rounded-lg hover:bg-muted/50 cursor-pointer transition-colors">
                        <h3 className="font-medium">Ver Logs</h3>
                        <p className="text-sm text-muted-foreground">Acompanhar atividades do sistema</p>
                    </div>
                    <div className="p-4 border rounded-lg hover:bg-muted/50 cursor-pointer transition-colors">
                        <h3 className="font-medium">Configurações</h3>
                        <p className="text-sm text-muted-foreground">Ajustar configurações globais</p>
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}
